export const generateFingerprint = Fingerprinter.generate;

/**
 * 🛠️ ADAPTER ESTRUTURAL (V4 - ABSOLUTE TRUTH)
 */
function normalizeIngestionInput(input: any) {
    if (Array.isArray(input)) return input;
    if (typeof input === 'string') {
        return {
            __rawText: input,
            __source: 'file'
        };
    }
    return input;
}

export const findMatchingModel = (content: string, models: FileModel[], fileName: string = ''): { model: FileModel, score: number } | null => {
    if (!models || models.length === 0) return null;
    const fileFp = Fingerprinter.generate(content);
    if (!fileFp) return null;

    // Identifica se é um placeholder de PDF
    const isPdfPlaceholder = content.includes('[DOCUMENTO_PDF_VISUAL]');

    if (isPdfPlaceholder) {
        // Busca todos os modelos que batem com o DNA de PDF
        const candidates = models.filter(m => m.is_active && m.fingerprint.headerHash === fileFp.headerHash);

        if (candidates.length === 0) return null;
        if (candidates.length === 1) return { model: candidates[0], score: 100 };

        // DESEMPATE INTELIGENTE: Se houver mais de um modelo de PDF, 
        // verifica qual nome de modelo está contido no nome do arquivo enviado.
        const fileKey = fileName.toLowerCase();
        const bestMatch = candidates.find(m => {
            const modelKey = m.name.toLowerCase().replace('.pdf', '').split('.')[0];
            return fileKey.includes(modelKey);
        }) || candidates[0];

        console.log(`[PDF:MATCHER] Ambiguidade resolvida para ${fileName} -> Aplicando: ${bestMatch.name}`);
        return { model: bestMatch, score: 100 };
    }

    // RIGOR ABSOLUTO para outros formatos (CSV/XLSX)
    const bestMatch = models.find(m => m.is_active && m.fingerprint.headerHash === fileFp.headerHash);
    return bestMatch ? { model: bestMatch, score: 100 } : null;
};

/**
 * PROCESSADOR DE PIPELINE (V17 - ABSOLUTE TRUTH ENFORCED)
 */
export const processFileContent = async (
    content: string, 
    fileName: string, 
    models: FileModel[] = [], 
    globalKeywords: string[] = [],
    base64?: string 
): Promise<StrategyResult & { appliedModel?: any }> => {

    const rawContent = IngestionOrchestrator.normalizeRawContent(content);

    // Passamos o fileName para ajudar na disambiguação de PDFs
    const matchResult = findMatchingModel(rawContent, models, fileName);
    const targetModel = matchResult?.model;

    const adaptedInput = {
        __rawText: rawContent,
        __base64: base64, 
        __source: 'file'
    };

    const result = await StrategyEngine.process(
        fileName, 
        adaptedInput, 
        models, 
        globalKeywords, 
        targetModel
    );

    if (result.status === 'MODEL_REQUIRED') {
        return result;
    }

    const transactions = Array.isArray(result?.transactions) ? result.transactions : [];

    return {
        ...result,
        transactions,
        appliedModel: targetModel ? { id: targetModel.id, name: targetModel.name, confidenceScore: 100 } : undefined
    };
};

export const parseContributors = (content: string, ignoreKeywords: string[] = [], typeKeywords: string[] = []): any[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 2) return [];
    const delimiter = Fingerprinter.detectDelimiter(lines[0]);
    const rows = lines.map(l => l.split(delimiter));

    const contributors = rows.slice(1).map(row => ({
        name: row[0] || 'Desconhecido',
        amount: parseFloat(String(row[1] || '0').replace(/[R$\s]/g, '').replace(',', '.')) || 0,
        date: row[2] || ''
    })).filter(c => c.name !== 'Desconhecido');

    return contributors;
};

import { GoogleGenAI, Type } from "@google/genai";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

let isAIBusy = false;

/**
 * 🛡️ PARSER RESILIENTE (V4 - ULTRA RECOVERY)
 */
const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();

    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    const tryParse = (str: string) => {
        try {
            const parsed = JSON.parse(str);
            if (parsed.rows) return parsed.rows;
            if (parsed.transactions) return parsed.transactions;
            return Array.isArray(parsed) ? parsed : null;
        } catch { return null; }
    };

    let result = tryParse(sanitized);
    if (result) return result;

    let lastBrace = sanitized.lastIndexOf('}');
    const possibleClosures = ['', ']', ']}', '"}]}', '"}'];

    while (lastBrace > 0) {
        const base = sanitized.substring(0, lastBrace + 1);
        for (const closure of possibleClosures) {
            const candidate = base + closure;
            result = tryParse(candidate);
            if (result) return result;
        }
        lastBrace = sanitized.lastIndexOf('}', lastBrace - 1);
    }

    return fallback;
};

/**
 * 🎯 MOTOR DE EXTRAÇÃO SEMÂNTICA (MODO PRESERVAÇÃO LITERAL ABSOLUTA)
 */
export const extractTransactionsWithModel = async (
    rawText: string, 
    modelContext?: string, 
    base64Data?: string,
    limit?: number
): Promise<any> => {
    if (isAIBusy) return { rows: [] };
    isAIBusy = true;

    try {
        const ai = getAIClient();

        const isPreview = !!limit;
        const limitInstruction = isPreview 
            ? `RESTRICAO: Apenas os primeiros ${limit} registros.`
            : `PROCESSAMENTO TOTAL: Extraia todos os dados sem exceção.`;

        const instruction = `VOCÊ É UM ROBÔ DE CÓPIA LITERAL (CÓPIA BIT-A-BIT). 
           Sua inteligência é avaliada pela fidelidade caractere-por-caractere com o documento original.

           --- CONTRATO DE EXTRAÇÃO (GABARITO ESTRUTURAL) ---
           ${modelContext}

           --- REGRAS DE OURO DE PRESERVAÇÃO ---
           1. FIDELIDADE TEXTUAL TOTAL: A 'description' deve ser copiada EXATAMENTE como aparece visualmente.
           2. DETECÇÃO DE SINAIS: Identifique se é Crédito ou Débito. Valores de saída (Débitos) devem ser SEMPRE negativos no JSON.
           3. FILTRAGEM: Extraia apenas as transações. Ignore headers de página e rodapés.
           ${limitInstruction}

           RETORNO OBRIGATÓRIO: JSON { "rows": [ { "date", "description", "amount", "forma", "tipo" } ] }`;

        const parts: any[] = [];
        if (base64Data) {
            parts.push({ inlineData: { data: base64Data, mimeType: 'application/pdf' } });
        } else {
            parts.push({ text: `CONTEÚDO PARA EXTRAÇÃO:\n${isPreview ? rawText.substring(0, 15000) : rawText}` });
        }
        parts.push({ text: instruction });

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', 
            contents: { parts },
            config: {
                temperature: 0,
                // Aumentado para suportar listas muito longas e evitar o corte em 24 linhas
                maxOutputTokens: 96000, 
                thinkingConfig: { thinkingBudget: 24000 },
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER },
                                    forma: { type: Type.STRING },
                                    tipo: { type: Type.STRING }
                                },
                                required: ["date", "description", "amount", "forma", "tipo"]
                            }
                        }
                    },
                    required: ["rows"]
                }
            }
        });

        return safeJsonParse(response.text);
    } finally {
        isAIBusy = false;
    }
};

